import React, {useState, useEffect} from "react";
import axios from "axios";

const API = "http://localhost:5000";

export default function App(){
  const [workflows,setWorkflows] = useState([]);
  const [name,setName] = useState("");

  useEffect(()=>{
    fetchWorkflows();
  },[]);

  const fetchWorkflows = async ()=>{
    const res = await axios.get(API+"/workflows");
    setWorkflows(res.data);
  }

  const createWorkflow = async ()=>{
    const wf = {
      name,
      steps:[
        {id:"step1", name:"Start", rules:[{condition:"DEFAULT", nextStepId:null}]}
      ]
    };
    await axios.post(API+"/workflows",wf);
    setName("");
    fetchWorkflows();
  }

  const runWorkflow = async(id)=>{
    const res = await axios.post(API+"/workflows/"+id+"/execute",{});
    alert(JSON.stringify(res.data.logs,null,2));
  }

  return (
    <div style={{padding:40,fontFamily:"Arial"}}>
      <h1>Workflow System</h1>

      <h3>Create Workflow</h3>
      <input value={name} onChange={e=>setName(e.target.value)} placeholder="Workflow name"/>
      <button onClick={createWorkflow}>Create</button>

      <h3>Workflows</h3>
      <ul>
        {workflows.map(w=>(
          <li key={w.id}>
            {w.name}
            <button onClick={()=>runWorkflow(w.id)}>Run</button>
          </li>
        ))}
      </ul>
    </div>
  )
}
